record.field:
# Configuración generada para {{ instance.name }} (Desarrollo) # {{ generated_at }}
[options] ; Conexión a base de datos db_host = db db_port = 5432 db_user = {{ db_user | default('odoo') }} db_password = {{ db_password }} db_name = {{ db_name | default(instance.subdomain or instance.code, true) }}
; Rutas data_dir = /var/lib/odoo addons_path = /usr/lib/python3/dist-packages/odoo/addons{% if REPO_SUBDIRS %}{% for dir in REPO_SUBDIRS %},/mnt/extra-addons/{{ dir }}{% endfor %}{% else %},/mnt/extra-addons{% endif %}
; Servidor HTTP http_port = 8069 http_interface = 0.0.0.0 gevent_port = 8072 proxy_mode = True
; Workers ; 0 = modo threaded (hot-reload); el websocket /websocket se sirve en el puerto ; HTTP (8069) — NO hay proceso gevent en 8072. ; >=1 = modo prefork; un proceso gevent sirve el websocket en gevent_port (8072). ; El routing de Traefik para /websocket se ajusta solo según este valor. ; Nota: la Terminal Web requiere un único HTTP worker (workers = 0 o 1). workers = {{ workers | default('0') }} max_cron_threads = 1
; Límites de recursos (más permisivos para desarrollo) limit_memory_hard = 4294967296 limit_memory_soft = 3221225472 limit_request = 8192 limit_time_cpu = 1200 limit_time_real = 2400
; Logging log_level = info log_handler = :INFO
; Seguridad (más permisivo para desarrollo) list_db = True admin_passwd = {{ admin_passwd }}
; Desarrollo dev_mode = reload,qweb,xml
